#include <stdio.h>
#include <string.h>
void partition(char* s, int start, int end, char*** result, int* returnSize, int** returnColumnSizes, int returnColumnSizesSize) {
    if (start == end) {
        *returnSize += 1;
        return;
    }
    for (int i = start; i < end; i++) {
        if (isPalindrome(s, start, i)) {
            partition(s, i + 1, end, result, returnSize, returnColumnSizes, returnColumnSizesSize);
        }
    }
}
int isPalindrome(char* s, int start, int end) {
    while (start < end) {
        if (s[start] != s[end]) return 0;
        start++;
        end--;
    }
    return 1;
}

