var partition = function(s) {
    const result = [];
    function backtrack(start, path) {
        if (start === s.length) {
            result.push([...path]);
            return;
        }
        for (let i = start; i < s.length; i++) {
            if (isPalindrome(s, start, i)) {
                path.push(s.slice(start, i + 1));
                backtrack(i + 1, path);
                path.pop();
            }
        }
    }
